#ifndef TOPK_SAMPLING_V128256_KERNEL_H
#define TOPK_SAMPLING_V128256_KERNEL_H

#include <cstdint>
#include <cuda_runtime.h>

constexpr int kVocabSizeV128256 = 128256;

void launch_top_k_sampling_from_probs_v128256(
    const float* probs,          // [B, 128256]
    const int32_t* top_k,         // [B]
    int64_t* samples,             // [B]
    int64_t batch_size,
    uint64_t seed,
    cudaStream_t stream);

#endif // TOPK_SAMPLING_V128256_KERNEL_H

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>
#include <limits.h>

#if !defined(__CUDA_ARCH__) || (__CUDA_ARCH__ >= 700)
  #define LDG(ptr) __ldg(ptr)
#else
  #define LDG(ptr) (*(ptr))
#endif

// RNG: splitmix64
__device__ __forceinline__ uint64_t splitmix64_next(uint64_t& state) {
  uint64_t x = (state += 0x9e3779b97f4a7c15ULL);
  x = (x ^ (x >> 30)) * 0xbf58476d1ce4e5b9ULL;
  x = (x ^ (x >> 27)) * 0x94d049bb133111ebULL;
  x = x ^ (x >> 31);
  return x;
}
__device__ __forceinline__ float u01_from_u32(uint32_t x) {
  return (static_cast<float>(x) + 0.5f) * (1.0f / 4294967296.0f);
}

// Warp/block reductions
__device__ __forceinline__ float warp_sum(float v) {
  #pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1)
    v += __shfl_down_sync(0xffffffff, v, offset);
  return v;
}

__device__ __forceinline__ int warp_min_int(int v) {
  #pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1)
    v = min(v, __shfl_down_sync(0xffffffff, v, offset));
  return v;
}

template<int BLOCK_THREADS>
__device__ __forceinline__ float block_sum(float v) {
  static_assert((BLOCK_THREADS % 32) == 0, "BLOCK_THREADS must be multiple of 32");
  constexpr int WARPS = BLOCK_THREADS / 32;
  __shared__ float warp_sums[WARPS];
  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;

  v = warp_sum(v);
  if (lane == 0) warp_sums[warp] = v;
  __syncthreads();

  float out = 0.0f;
  if (warp == 0) {
    out = (lane < WARPS) ? warp_sums[lane] : 0.0f;
    out = warp_sum(out);
  }
  return __shfl_sync(0xffffffff, out, 0);
}

template<int BLOCK_THREADS>
__device__ __forceinline__ int block_min_int(int v) {
  static_assert((BLOCK_THREADS % 32) == 0, "BLOCK_THREADS must be multiple of 32");
  constexpr int WARPS = BLOCK_THREADS / 32;
  __shared__ int warp_mins[WARPS];
  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;

  v = warp_min_int(v);
  if (lane == 0) warp_mins[warp] = v;
  __syncthreads();

  int out = INT_MAX;
  if (warp == 0) {
    out = (lane < WARPS) ? warp_mins[lane] : INT_MAX;
    out = warp_min_int(out);
  }
  return __shfl_sync(0xffffffff, out, 0);
}

// Float->key (non-negative)
__device__ __forceinline__ uint32_t float_to_key_nonneg(float x) {
  x = (x >= 0.0f) ? x : 0.0f;
  return __float_as_uint(x);
}

// Full multinomial (no top-k)
template<int BLOCK_THREADS>
__device__ __forceinline__ int64_t sample_full_multinomial_streaming(
    const float* __restrict__ row,
    uint64_t rng_state)
{
  constexpr int V = kVocabSizeV128256;

  float local_sum = 0.0f;
  for (int i = threadIdx.x; i < V; i += BLOCK_THREADS) local_sum += LDG(row + i);

  float total = block_sum<BLOCK_THREADS>(local_sum);
  total = (total > 0.0f) ? total : 1.0f;

  uint32_t r = (uint32_t)splitmix64_next(rng_state);
  float target = u01_from_u32(r) * total;

  __shared__ float sh_sums[BLOCK_THREADS];
  sh_sums[threadIdx.x] = local_sum;
  __syncthreads();

  float x = sh_sums[threadIdx.x];
  for (int offset = 1; offset < BLOCK_THREADS; offset <<= 1) {
    float add = (threadIdx.x >= offset) ? sh_sums[threadIdx.x - offset] : 0.0f;
    __syncthreads();
    sh_sums[threadIdx.x] = x + add;
    __syncthreads();
    x = sh_sums[threadIdx.x];
  }
  float prefix_before = x - local_sum;

  int candidate_tid = INT_MAX;
  int64_t candidate_idx = -1;

  if (target < prefix_before + local_sum) {
    float acc = prefix_before;
    for (int i = threadIdx.x; i < V; i += BLOCK_THREADS) {
      float p = LDG(row + i);
      float next = acc + p;
      if (target < next) { candidate_tid = threadIdx.x; candidate_idx = (int64_t)i; break; }
      acc = next;
    }
    if (candidate_idx < 0) { candidate_tid = threadIdx.x; candidate_idx = (int64_t)(V - 1); }
  }

  int winner = block_min_int<BLOCK_THREADS>(candidate_tid);
  __shared__ int64_t sh_pick;
  if (threadIdx.x == winner) sh_pick = candidate_idx;
  __syncthreads();
  return sh_pick;
}

// Radix select: kth largest key
template<int BLOCK_THREADS>
__device__ __forceinline__ uint32_t select_kth_largest_key_radix(
    const float* __restrict__ row, int k)
{
  constexpr int V = kVocabSizeV128256;

  uint32_t prefix = 0;
  uint32_t mask = 0;

  for (int pass = 3; pass >= 0; --pass) {
    __shared__ int hist[256];
    if (threadIdx.x < 256) hist[threadIdx.x] = 0;
    __syncthreads();

    const int shift = pass * 8;

    for (int i = threadIdx.x; i < V; i += BLOCK_THREADS) {
      uint32_t key = float_to_key_nonneg(LDG(row + i));
      if ((key & mask) == prefix) {
        uint32_t bin = (key >> shift) & 0xffu;
        atomicAdd(&hist[bin], 1);
      }
    }
    __syncthreads();

    __shared__ uint32_t scratch_prefix, scratch_mask;
    __shared__ int scratch_k;
    if (threadIdx.x == 0) {
      int chosen = 0;
      int suffix_gt = 0;
      for (int b = 255; b >= 0; --b) {
        int cnt = hist[b];
        int cnt_ge = suffix_gt + cnt;
        if (cnt_ge >= k) { chosen = b; break; }
        suffix_gt = cnt_ge;
      }
      k -= suffix_gt;

      prefix |= (uint32_t)chosen << shift;
      mask   |= 0xffu << shift;

      scratch_k = k;
      scratch_prefix = prefix;
      scratch_mask = mask;
    }
    __syncthreads();
    k = scratch_k;
    prefix = scratch_prefix;
    mask = scratch_mask;
  }
  return prefix;
}

// Radix select: kth smallest index among equals to kth_key
template<int BLOCK_THREADS>
__device__ __forceinline__ uint32_t select_kth_smallest_index_among_equals(
    const float* __restrict__ row,
    uint32_t kth_key,
    int k_smallest)
{
  constexpr int V = kVocabSizeV128256;
  uint32_t prefix = 0;
  uint32_t mask = 0;

  for (int pass = 3; pass >= 0; --pass) {
    __shared__ int hist[256];
    if (threadIdx.x < 256) hist[threadIdx.x] = 0;
    __syncthreads();

    const int shift = pass * 8;
    for (int i = threadIdx.x; i < V; i += BLOCK_THREADS) {
      uint32_t key = float_to_key_nonneg(LDG(row + i));
      if (key == kth_key) {
        uint32_t idx = (uint32_t)i;
        if ((idx & mask) == prefix) {
          uint32_t bin = (idx >> shift) & 0xffu;
          atomicAdd(&hist[bin], 1);
        }
      }
    }
    __syncthreads();

    __shared__ uint32_t scratch_prefix, scratch_mask;
    __shared__ int scratch_k;
    if (threadIdx.x == 0) {
      int running = 0;
      int chosen = 0;
      for (int b = 0; b < 256; ++b) {
        int cnt = hist[b];
        if (running + cnt >= k_smallest) { chosen = b; break; }
        running += cnt;
      }
      k_smallest -= running;

      prefix |= (uint32_t)chosen << shift;
      mask   |= 0xffu << shift;

      scratch_k = k_smallest;
      scratch_prefix = prefix;
      scratch_mask = mask;
    }
    __syncthreads();
    k_smallest = scratch_k;
    prefix = scratch_prefix;
    mask = scratch_mask;
  }
  return prefix;
}

template<int BLOCK_THREADS>
__global__ void top_k_sampling_from_probs_v128256_kernel(
    const float* __restrict__ probs,
    const int32_t* __restrict__ top_k,
    int64_t* __restrict__ samples,
    int64_t batch_size,
    uint64_t seed)
{
  const int b = (int)blockIdx.x;
  if ((int64_t)b >= batch_size) return;

  const float* row = probs + (int64_t)b * (int64_t)kVocabSizeV128256;
  int k = (int)LDG(top_k + b);

  uint64_t rng = seed ^ (0x9e3779b97f4a7c15ULL * (uint64_t)(b + 1));

  if (!(0 < k && k < kVocabSizeV128256)) {
    int64_t pick = sample_full_multinomial_streaming<BLOCK_THREADS>(row, rng);
    if (threadIdx.x == 0) samples[b] = pick;
    return;
  }

  uint32_t kth_key = select_kth_largest_key_radix<BLOCK_THREADS>(row, k);

  int gt_cnt_local = 0;
  int eq_cnt_local = 0;
  for (int i = threadIdx.x; i < kVocabSizeV128256; i += BLOCK_THREADS) {
    uint32_t key = float_to_key_nonneg(LDG(row + i));
    if (key > kth_key) gt_cnt_local++;
    else if (key == kth_key) eq_cnt_local++;
  }

  // FIX: avoid atomicAdd on shared scalars (can be flaky on some toolchains); use block sums.
  int sh_gt_cnt = (int)block_sum<BLOCK_THREADS>((float)gt_cnt_local);
  int sh_eq_cnt = (int)block_sum<BLOCK_THREADS>((float)eq_cnt_local);

  int need_from_eq = k - sh_gt_cnt;
  if (need_from_eq < 0) need_from_eq = 0;
  if (need_from_eq > sh_eq_cnt) need_from_eq = sh_eq_cnt;

  uint32_t eq_index_threshold = 0xffffffffu;
  if (need_from_eq > 0) {
    eq_index_threshold = select_kth_smallest_index_among_equals<BLOCK_THREADS>(
        row, kth_key, need_from_eq);
  }

  float sel_sum_local = 0.0f;
  for (int i = threadIdx.x; i < kVocabSizeV128256; i += BLOCK_THREADS) {
    float p = LDG(row + i);
    uint32_t key = float_to_key_nonneg(p);
    if (key > kth_key) sel_sum_local += p;
    else if (need_from_eq > 0 && key == kth_key && (uint32_t)i <= eq_index_threshold) sel_sum_local += p;
  }
  float sel_sum = block_sum<BLOCK_THREADS>(sel_sum_local);
  sel_sum = (sel_sum > 0.0f) ? sel_sum : 1.0f;

  uint32_t r2 = (uint32_t)splitmix64_next(rng);
  float target = u01_from_u32(r2) * sel_sum;

  __shared__ float sh_sel[BLOCK_THREADS];
  sh_sel[threadIdx.x] = sel_sum_local;
  __syncthreads();

  float x = sh_sel[threadIdx.x];
  for (int offset = 1; offset < BLOCK_THREADS; offset <<= 1) {
    float add = (threadIdx.x >= offset) ? sh_sel[threadIdx.x - offset] : 0.0f;
    __syncthreads();
    sh_sel[threadIdx.x] = x + add;
    __syncthreads();
    x = sh_sel[threadIdx.x];
  }
  float prefix_before = x - sel_sum_local;

  int local_tid = INT_MAX;
  int64_t local_pick = -1;

  if (target < prefix_before + sel_sum_local) {
    float acc = prefix_before;
    for (int i = threadIdx.x; i < kVocabSizeV128256; i += BLOCK_THREADS) {
      float p = LDG(row + i);
      uint32_t key = float_to_key_nonneg(p);
      bool sel = (key > kth_key) || (need_from_eq > 0 && key == kth_key && (uint32_t)i <= eq_index_threshold);
      if (!sel) continue;
      float next = acc + p;
      if (target < next) { local_tid = threadIdx.x; local_pick = (int64_t)i; break; }
      acc = next;
    }
    if (local_pick < 0) { local_tid = threadIdx.x; local_pick = (int64_t)(kVocabSizeV128256 - 1); }
  }

  int winner = block_min_int<BLOCK_THREADS>(local_tid);
  __shared__ int64_t sh_pick;
  if (threadIdx.x == winner) sh_pick = local_pick;
  __syncthreads();
  if (threadIdx.x == 0) samples[b] = sh_pick;
}

void launch_top_k_sampling_from_probs_v128256(
    const float* probs,
    const int32_t* top_k,
    int64_t* samples,
    int64_t batch_size,
    uint64_t seed,
    cudaStream_t stream)
{
  constexpr int BLOCK = 256;
  dim3 block(BLOCK);
  dim3 grid((unsigned)batch_size);
  top_k_sampling_from_probs_v128256_kernel<BLOCK><<<grid, block, 0, stream>>>(
      probs, top_k, samples, batch_size, seed);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#include <cstdint>
#include <stdexcept>
#include <string>

#include "kernel.h"

static inline void check_cuda_contig(const torch::Tensor& t, const char* name) {
  if (!t.defined()) throw std::runtime_error(std::string(name) + " is undefined");
  if (!t.device().is_cuda()) throw std::runtime_error(std::string(name) + " must be a CUDA tensor");
  if (!t.is_contiguous()) throw std::runtime_error(std::string(name) + " must be contiguous");
}

torch::Tensor run(torch::Tensor probs,
                  torch::Tensor top_k,
                  c10::optional<int64_t> seed_opt = c10::nullopt) {
  check_cuda_contig(probs, "probs");
  check_cuda_contig(top_k, "top_k");

  if (probs.dtype() != torch::kFloat32)
    throw std::runtime_error("probs must be torch.float32");
  if (top_k.dtype() != torch::kInt32)
    throw std::runtime_error("top_k must be torch.int32");

  if (probs.dim() != 2)
    throw std::runtime_error("probs must have shape [batch_size, vocab_size]");
  if (top_k.dim() != 1)
    throw std::runtime_error("top_k must have shape [batch_size]");

  const int64_t batch_size = probs.size(0);
  const int64_t vocab_size = probs.size(1);

  if (vocab_size != kVocabSizeV128256)
    throw std::runtime_error("vocab_size must be exactly 128256");
  if (top_k.size(0) != batch_size)
    throw std::runtime_error("top_k.size(0) must equal probs.size(0)");

  auto samples = torch::empty({batch_size},
                              torch::TensorOptions().device(probs.device()).dtype(torch::kInt64));

  const float* probs_ptr = probs.data_ptr<float>();
  const int32_t* topk_ptr = top_k.data_ptr<int32_t>();
  int64_t* out_ptr = samples.data_ptr<int64_t>();

  uint64_t seed = seed_opt.has_value()
      ? static_cast<uint64_t>(*seed_opt)
      : 0x1234abcd5678eeffULL;

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  launch_top_k_sampling_from_probs_v128256(probs_ptr, topk_ptr, out_ptr, batch_size, seed, stream);

  cudaError_t e = cudaGetLastError();
  if (e != cudaSuccess) {
    throw std::runtime_error(std::string("CUDA launch failed: ") + cudaGetErrorString(e));
  }
  e = cudaStreamSynchronize(stream);
  if (e != cudaSuccess) {
    throw std::runtime_error(std::string("cudaStreamSynchronize failed: ") + cudaGetErrorString(e));
  }

  return samples;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "top_k_sampling_from_probs_v128256 (CUDA)",
        py::arg("probs"),
        py::arg("top_k"),
        py::arg("seed") = c10::nullopt);
}
